function initNavigation() {
  let e = document.querySelectorAll(".site-nav__link");
  e.forEach((t) => {
    t.addEventListener("click", () => {
      (e.forEach((e) => e.classList.remove("site-nav__link--active")),
        t.classList.add("site-nav__link--active"));
    });
  });
}
function initCarousel(e) {
  let t = e.querySelector(".carousel__viewport"),
    l = e.querySelectorAll(".carousel__slide"),
    i = e.querySelector(".carousel__btn--prev"),
    r = e.querySelector(".carousel__btn--next");
  if (!t || !i || !r || 0 === l.length) return;
  let n = () => l[0].clientWidth,
    o = () => {
      let e = n(),
        l = t.scrollWidth - t.clientWidth;
      ((i.disabled = t.scrollLeft <= 0),
        (r.disabled = t.scrollLeft >= l - e / 2));
    };
  (r.addEventListener("click", () => {
    t.scrollBy({ left: n(), behavior: "smooth" });
  }),
    i.addEventListener("click", () => {
      t.scrollBy({ left: -n(), behavior: "smooth" });
    }),
    t.addEventListener("scroll", () => {
      window.requestAnimationFrame(o);
    }),
    window.addEventListener("resize", o),
    o());
}
document.addEventListener("DOMContentLoaded", () => {
  (initNavigation(),
    document.querySelectorAll(".carousel").forEach(initCarousel));
});
